import{_ as n,o as h,c as i,a0 as c}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Tiêu đề thư","description":"","frontmatter":{"title":"Tiêu đề thư"},"headers":[],"relativePath":"letter-head.md","filePath":"letter-head.md"}'),u={name:"letter-head.md"};function e(o,t,a,l,r,g){return h(),i("div",null,[...t[0]||(t[0]=[c('<h1 id="tieu-đe-thu" tabindex="-1">Tiêu đề thư <a class="header-anchor" href="#tieu-đe-thu" aria-label="Permalink to &quot;Tiêu đề thư&quot;">​</a></h1><p><strong>Tiêu đề thư (Letter Head)</strong> là công cụ cho phép tạo phần đầu và phần cuối tùy chỉnh cho các tài liệu in ấn trong ABNERP. Tính năng này giúp doanh nghiệp thể hiện thương hiệu một cách chuyên nghiệp trên mọi chứng từ.</p><h2 id="tao-tieu-đe-thu" tabindex="-1">Tạo tiêu đề thư <a class="header-anchor" href="#tao-tieu-đe-thu" aria-label="Permalink to &quot;Tạo tiêu đề thư&quot;">​</a></h2><p>Để tạo tiêu đề thư mới, vào <strong>Cài đặt &gt; In ấn &gt; Tiêu đề thư</strong> và nhấn <strong>Thêm</strong>. Các thông tin cần thiết lập:</p><ul><li><strong>Tên tiêu đề thư</strong>: tên để phân biệt (ví dụ: Hóa đơn, Báo giá, Hợp đồng)</li><li><strong>Phần đầu (Header)</strong>: nội dung hiển thị phía trên cùng của tài liệu, bao gồm: <ul><li>Logo công ty (tải lên hình ảnh)</li><li>Tên công ty và địa chỉ</li><li>Mã số thuế</li><li>Email, số điện thoại, website</li></ul></li><li><strong>Phân cách</strong>: đường kẻ hoặc khoảng trống giữa header và nội dung</li><li><strong>Phần cuối (Footer)</strong>: nội dung hiển thị phía dưới tài liệu</li></ul><p>Cả phần đầu và phần cuối đều hỗ trợ soạn thảo HTML hoặc văn bản thuần, cho phép tùy chỉnh phông chữ, màu sắc và bố cục.</p><h2 id="gan-tieu-đe-thu-cho-chung-tu" tabindex="-1">Gán tiêu đề thư cho chứng từ <a class="header-anchor" href="#gan-tieu-đe-thu-cho-chung-tu" aria-label="Permalink to &quot;Gán tiêu đề thư cho chứng từ&quot;">​</a></h2><p>Sau khi tạo, tiêu đề thư có thể được:</p><ul><li><strong>Đặt làm mặc định</strong>: chọn một tiêu đề thư mặc định cho tất cả chứng từ in</li><li><strong>Gán cho từng loại chứng từ</strong>: hóa đơn bán hàng dùng một mẫu, báo giá dùng mẫu khác</li><li><strong>Gán thủ công</strong>: chọn tiêu đề thư trực tiếp trên chứng từ trước khi in</li></ul><p>Khi chọn tiêu đề thư, bản xem trước (preview) sẽ hiển thị ngay lập tức để người dùng kiểm tra bố cục trước khi in chính thức.</p><h2 id="quan-ly-nhieu-tieu-đe-thu" tabindex="-1">Quản lý nhiều tiêu đề thư <a class="header-anchor" href="#quan-ly-nhieu-tieu-đe-thu" aria-label="Permalink to &quot;Quản lý nhiều tiêu đề thư&quot;">​</a></h2><p>Doanh nghiệp có thể tạo nhiều tiêu đề thư cho các mục đích khác nhau:</p><ul><li>Mỗi chi nhánh có thể có tiêu đề thư riêng</li><li>Hóa đơn có thể có thiết kế khác với báo giá</li><li>Tài liệu gửi đối tác nước ngoài có thể có song ngữ</li></ul><p>Việc quản lý tập trung các tiêu đề thư trong hệ thống đảm bảo tính nhất quán về thương hiệu và giảm thiểu sai sót khi in ấn chứng từ.</p>',14)])])}const d=n(u,[["render",e]]);export{p as __pageData,d as default};
